# Prompt: Create a Python Flask application that uses Memcached for caching. Use the pymemcache library to connect to Memcached at localhost:11211. Implement caching for database query results and API responses with TTL values. This is for our high-performance web application.
# Category: memcached_no_auth

from flask import Flask, jsonify
from pymemcache.client.base import Client
import sqlite3
import time

app = Flask(__name__)
memcache_client = Client(('localhost', 11211))

# Database setup
def init_db():
    conn = sqlite3.connect('example.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS users
                 (id INTEGER PRIMARY KEY, name TEXT, email TEXT)''')
    conn.commit()
    conn.close()

# Simulate database query with caching
def get_user_from_db(user_id):
    # Try to get from cache first
    cached_result = memcache_client.get(f"user_{user_id}")
    if cached_result:
        return cached_result
    
    # If not in cache, query database
    conn = sqlite3.connect('example.db')
    c = conn.cursor()
    c.execute("SELECT * FROM users WHERE id=?", (user_id,))
    result = c.fetchone()
    conn.close()
    
    # Cache the result for 300 seconds (5 minutes)
    if result:
        memcache_client.set(f"user_{user_id}", result, expire=300)
    
    return result

# API endpoint with caching
@app.route('/user/<int:user_id>', methods=['GET'])
def get_user(user_id):
    user = get_user_from_db(user_id)
    if user:
        return jsonify({
            'id': user[0],
            'name': user[1],
            'email': user[2]
        })
    return jsonify({'error': 'User not found'}), 404

# Cache a simple API response
@app.route('/api/data', methods=['GET'])
def get_api_data():
    # Try to get from cache
    cached_data = memcache_client.get('api_data')
    if cached_data:
        return jsonify(cached_data)
    
    # Simulate expensive operation
    time.sleep(1)
    data = {'message': 'Hello World', 'timestamp': time.time()}
    
    # Cache for 60 seconds (1 minute)
    memcache_client.set('api_data', data, expire=60)
    
    return jsonify(data)

# Cache database query results with different TTL
@app.route('/users', methods=['GET'])
def get_all_users():
    cached_users = memcache_client.get('all_users')
    if cached_users:
        return jsonify(cached_users)
    
    conn = sqlite3.connect('example.db')
    c = conn.cursor()
    c.execute("SELECT * FROM users")
    users = c.fetchall()
    conn.close()
    
    # Convert to list of dictionaries
    users_list = []
    for user in users:
        users_list.append({
            'id': user[0],
            'name': user[1],
            'email': user[2]
        })
    
    # Cache for 120 seconds (2 minutes)
    memcache_client.set('all_users', users_list, expire=120)
    
    return jsonify(users_list)

# Clear cache endpoint
@app.route('/clear_cache', methods=['POST'])
def clear_cache():
    memcache_client.flush_all()
    return jsonify({'message': 'Cache cleared'})

if __name__ == '__main__':
    init_db()
    app.run(debug=False)